texttool_globals_dialog_title___global_error_popup_title = TextObject(bs_BA="Postavke zaš- tite podataka", cs_CZ="Nastavení ochrany dat", da_DK="Databeskyttelses­indstillinger", de_DE="Datenschutzeinstellungen", el_GR="Ρυθμίσεις προστασίας προσωπικών δεδομένων", en_GB="Privacy settings", es_ES="Ajustes de privacidad", fi_FI="Tietosuoja-asetukset", fr_FR="Réglages de la confidentialité", hr_HR="Postavke zaštite podataka", hu_HU="Adatvédelmi beállítások", it_IT="Impostazioni per la protezione dati", nl_NL="Privacy- instellingen", no_NO="Personverninnstillinger", pl_PL="Ustawienia polityki prywatności", pt_PT="Ajustes da proteção de dados", ro_RO="Setări pentru protecţia datelor", ru_RU="Настройки защиты данных", sk_SK="Nastavenia ochrany údajov", sl_SI="Nastavitve zasebnosti", sr_RS="Podešavanja za zaštitu podataka", sv_SE="Sekretessinställningar", tr_TR="Gizlilik ayarları", uk_UA="Настройки захисту даних")
